import random
import time

class Lift:
    def __init__(self, num_floors):
        self.current_floor = 0
        self.num_floors = num_floors
        self.passengers = []
        self.direction = 0
        self.waiting_passengers = [0] * num_floors

    def move(self):
        if self.direction == 0:
            return
        if self.direction == 1:
            self.current_floor = min(self.current_floor + 1, self.num_floors - 1)
        else:
            self.current_floor = max(self.current_floor - 1, 0)
        self.passengers = [p for p in self.passengers if p != self.current_floor]
        for i in range(len(self.waiting_passengers)):
            if i == self.current_floor:
                self.passengers.extend([i] * self.waiting_passengers[i])
                self.waiting_passengers[i] = 0

    def call(self, floor, direction):
        self.waiting_passengers[floor] += 1
        if direction == 0 or self.direction == 0 or direction == self.direction:
            self.direction = direction

class Building:
    def __init__(self, num_floors, num_lifts):
        self.num_floors = num_floors
        self.num_lifts = num_lifts
        self.lifts = [Lift(num_floors) for _ in range(num_lifts)]
        self.passenger_arrivals = [0] * (num_floors * 24)

    def run_simulation(self, num_passengers, start_time, end_time):
        for t in range(start_time, end_time):
            for _ in range(self.passenger_arrivals[t]):
                self.add_passenger(random.randint(0, self.num_floors - 1), random.randint(0, self.num_floors - 1))
            for lift in self.lifts:
                lift.move()
            time.sleep(0.1)

    def add_passenger(self, from_floor, to_floor):
        if from_floor == to_floor:
            return
        direction = 1 if from_floor < to_floor else -1
        closest_lift = min(self.lifts, key=lambda l: abs(l.current_floor - from_floor))
        closest_lift.call(from_floor, direction)

def main():
    num_floors = 50
    num_lifts = 5
    num_passengers = 1000
    building = Building(num_floors, num_lifts)

    for hour in range(24):
        for minute in range(0, 60, 10):
            time = hour * 60 + minute
            if time < 8 * 60 or time > 19 * 60:
                building.passenger_arrivals[time] = 0
            elif time < 9 * 60:
                building.passenger_arrivals[time] = num_passengers // 3
            elif time < 18 * 60:
                building.passenger_arrivals[time] = num_passengers // 10
            else:
                building.passenger_arrivals[time] = num_passengers // 3

    building.run_simulation(num_passengers, 0, 24 * 60)

if __name__ == "__main__":
    main()

